package com.example.nofiltercoffee; import android.content.*; import android.os.*; import android.widget.*; import androidx.appcompat.app.*; public class SplashActivity extends AppCompatActivity{protected void onCreate(Bundle b){super.onCreate(b);setContentView(R.layout.activity_splash);new Handler().postDelayed(()->{Intent i=new Intent(this,UserSession.isLoggedIn(this)?HomeActivity.class:(UserSession.hasAccount(this)?LoginActivity.class:SignupActivity.class));startActivity(i);finish();},1400);}}
